     1→import React, { useEffect, useState } from 'react';
     2→import { Link, useLocation } from 'react-router-dom';
     3→import { useSidebarStore } from '../stores/useSidebarStore';
     4→import { useSidebarNavStore } from '../stores/useSidebarNavStore';
     5→import { useNavExpansionStore } from '../stores/useNavExpansionStore';
     6→import { useThemeStore } from '../stores/useThemeStore';
     7→import { PageSettingsPanel } from './PageSettingsPanel';
     8→import { TimeTrackingPanel } from './TimeTrackingPanel';
     9→import { useNotesStore } from '../stores/useNotesStore';
    10→import { useNavigate } from 'react-router-dom';
    11→import { useSettingsStore } from '../stores/useSettingsStore';
    12→import { DndContext, closestCenter, PointerSensor, useSensor, useSensors } from '@dnd-kit/core';
    13→import type { DragEndEvent } from '@dnd-kit/core';
    14→import { SortableContext, verticalListSortingStrategy, useSortable, arrayMove } from '@dnd-kit/sortable';
    15→import { CSS } from '@dnd-kit/utilities';
    16→
    17→/**
    18→ * FOUNDATIONAL: NavItem interface with expandable support
    19→ * Any nav item can have sub-pages by adding `children`.
    20→ */
    21→interface NavItem {
    22→  icon: string;
    23→  label: string;
    24→  path: string;
    25→  shortcut?: string;
    26→  hasSettings?: boolean; // Whether this page has custom settings
    27→  children?: NavItem[]; // Sub-pages (expandable)
    28→  defaultExpanded?: boolean; // Initial expansion state
    29→}
    30→
    31→// Fixed navigation items (always at top, not draggable)
    32→const fixedNavigation: NavItem[] = [
    33→  {
    34→    icon: '🏠',
    35→    label: 'Dashboard',
    36→    path: '/',
    37→    shortcut: 'D',
    38→    hasSettings: true,
    39→    defaultExpanded: true,
    40→    children: [
    41→      { icon: '🔗', label: 'Link Library', path: '/links' },
    42→    ],
    43→  },
    44→  {
    45→    icon: '📅',
    46→    label: 'Schedule',
    47→    path: '/schedule',
    48→    shortcut: 'P',
    49→    hasSettings: false,
    50→    defaultExpanded: false,
    51→    children: [
    52→      { icon: '⏱️', label: 'Timer', path: '/schedule?tab=timer' },
    53→      { icon: '📋', label: 'Entries', path: '/schedule?tab=entries' },
    54→      { icon: '📊', label: 'Summary', path: '/schedule?tab=summary' },
    55→      { icon: '📆', label: 'Calendar', path: '/schedule?tab=calendar' },
    56→      { icon: '📁', label: 'Projects', path: '/schedule?tab=projects' },
    57→    ],
    58→  },
    59→];
    60→
    61→// Draggable navigation items (user can reorganize)
    62→const draggableNavigation: NavItem[] = [
    63→  {
    64→    icon: '📝',
    65→    label: 'Notes',
    66→    path: '/notes',
    67→    shortcut: 'N',
    68→    hasSettings: false,
    69→    defaultExpanded: false,
    70→    children: [
    71→      { icon: '🕸️', label: 'Graph', path: '/graph' },
    72→      { icon: '📊', label: 'Diagrams', path: '/diagrams' },
    73→      { icon: '📋', label: 'Forms', path: '/forms' },
    74→    ],
    75→  },
    76→  { icon: '✓', label: 'Tasks', path: '/tasks', shortcut: 'T', hasSettings: false },
    77→];
    78→
    79→// Sortable Navigation Item Component
    80→interface SortableNavItemProps {
    81→  item: NavItem;
    82→  isCollapsed: boolean;
    83→  isActive: boolean;
    84→  onPageSettings: (e: React.MouseEvent, path: string) => void;
    85→  justDragged: boolean;
    86→}
    87→
    88→const SortableNavItem: React.FC<SortableNavItemProps> = ({ item, isCollapsed, isActive, onPageSettings, justDragged }) => {
    89→  const {
    90→    attributes,
    91→    listeners,
    92→    setNodeRef,
    93→    transform,
    94→    transition,
    95→    isDragging,
    96→  } = useSortable({ id: item.path });
    97→
    98→  const location = useLocation();
    99→  const { isExpanded, toggleExpanded } = useNavExpansionStore();
   100→  const hasChildren = item.children && item.children.length > 0;
   101→  const expanded = isExpanded(item.path);
   102→
   103→  const style = {
   104→    transform: CSS.Transform.toString(transform),
   105→    transition,
   106→    opacity: isDragging ? 0.5 : 1,
   107→  };
   108→
   109→  // Check if any child is active
   110→  const isChildActive = (navItem: NavItem) => {
   111→    if (!navItem.children) return false;
   112→    return navItem.children.some((child) => {
   113→      // Handle paths with query params
   114→      if (child.path.includes('?')) {
   115→        const [pathname, query] = child.path.split('?');
   116→        if (location.pathname !== pathname) return false;
   117→        const params = new URLSearchParams(query);
   118→        const currentParams = new URLSearchParams(location.search);
   119→        for (const [key, value] of params.entries()) {
   120→          if (currentParams.get(key) !== value) return false;
   121→        }
   122→        return true;
   123→      }
   124→      return location.pathname === child.path;
   125→    });
   126→  };
   127→
   128→  const childActive = isChildActive(item);
   129→
   130→  return (
   131→    <li ref={setNodeRef} style={style} {...attributes}>
   132→      <Link
   133→        to={item.path}
   134→        onClick={(e) => {
   135→          if (justDragged) {
   136→            e.preventDefault();
   137→          }
   138→        }}
   139→        className={`
   140→          flex items-center gap-3 px-3 h-10 rounded-button
   141→          transition-all duration-standard ease-smooth
   142→          relative group
   143→          ${
   144→            isActive || childActive
   145→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   146→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   147→          }
   148→        `}
   149→        title={isCollapsed ? item.label : undefined}
   150→      >
   151→        {/* Active indicator (left accent) */}
   152→        {isActive && (
   153→          <div className="absolute left-0 top-2 bottom-2 w-[3px] bg-accent-blue rounded-r" />
   154→        )}
   155→
   156→        {/* Icon - Fixed 20px size */}
   157→        <span className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg">
   158→          {item.icon}
   159→        </span>
   160→
   161→        {/* Label (hidden when collapsed) */}
   162→        {!isCollapsed && (
   163→          <>
   164→            <span className="flex-1 text-base leading-5 font-medium truncate">
   165→              {item.label}
   166→            </span>
   167→
   168→            {/* Page Settings Icon (shown on hover) */}
   169→            {item.hasSettings && (
   170→              <button
   171→                onClick={(e) => onPageSettings(e, item.path)}
   172→                className="
   173→                  opacity-0 group-hover:opacity-100
   174→                  w-5 h-5 flex items-center justify-center flex-shrink-0
   175→                  text-text-light-secondary dark:text-text-dark-secondary
   176→                  hover:text-text-light-primary dark:hover:text-text-dark-primary
   177→                  transition-opacity duration-200
   178→                "
   179→                title="Page Settings"
   180→                aria-label={`${item.label} page settings`}
   181→              >
   182→                <span className="text-sm">⚙</span>
   183→              </button>
   184→            )}
   185→
   186→            {/* Expand/Collapse Chevron (for items with children) */}
   187→            {hasChildren && (
   188→              <button
   189→                onClick={(e) => {
   190→                  e.preventDefault();
   191→                  e.stopPropagation();
   192→                  toggleExpanded(item.path);
   193→                }}
   194→                className="
   195→                  w-5 h-5 flex items-center justify-center flex-shrink-0
   196→                  text-text-light-secondary dark:text-text-dark-secondary
   197→                  hover:text-text-light-primary dark:hover:text-text-dark-primary
   198→                  transition-transform duration-200
   199→                "
   200→                title={expanded ? 'Collapse' : 'Expand'}
   201→              >
   202→                <span
   203→                  className={`text-xs transition-transform duration-200 ${
   204→                    expanded ? 'rotate-90' : ''
   205→                  }`}
   206→                >
   207→                  ▶
   208→                </span>
   209→              </button>
   210→            )}
   211→
   212→            {/* Drag handle - visible on hover (right side) */}
   213→            <div
   214→              {...listeners}
   215→              className="cursor-grab active:cursor-grabbing opacity-0 group-hover:opacity-100 transition-opacity w-5 h-5 flex items-center justify-center flex-shrink-0"
   216→              title="Drag to reorder"
   217→              role="button"
   218→              aria-label={`Drag ${item.label} to reorder`}
   219→              tabIndex={0}
   220→            >
   221→              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">⋮⋮</span>
   222→            </div>
   223→          </>
   224→        )}
   225→
   226→        {/* Tooltip for collapsed state */}
   227→        {isCollapsed && (
   228→          <div className="
   229→            absolute left-full ml-2 px-2 py-1
   230→            bg-surface-light-elevated dark:bg-surface-dark-elevated
   231→            text-text-light-primary dark:text-text-dark-primary text-xs rounded
   232→            opacity-0 group-hover:opacity-100
   233→            pointer-events-none transition-opacity duration-200
   234→            whitespace-nowrap z-50
   235→          ">
   236→            {item.label}
   237→          </div>
   238→        )}
   239→      </Link>
   240→
   241→      {/* Children (Sub-pages) - only show when expanded and not collapsed */}
   242→      {hasChildren && expanded && !isCollapsed && (
   243→        <ul className="ml-6 mt-1 space-y-1">
   244→          {item.children!.map((child) => (
   245→            <li key={child.path}>
   246→              <Link
   247→                to={child.path}
   248→                className={`
   249→                  flex items-center gap-3 px-3 h-9 rounded-button
   250→                  transition-all duration-standard ease-smooth
   251→                  relative group
   252→                  ${
   253→                    location.pathname === child.path
   254→                      ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   255→                      : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   256→                  }
   257→                `}
   258→              >
   259→                {/* Active indicator (left accent) */}
   260→                {location.pathname === child.path && (
   261→                  <div className="absolute left-0 top-1.5 bottom-1.5 w-[3px] bg-accent-blue rounded-r" />
   262→                )}
   263→
   264→                {/* Icon */}
   265→                <span className="w-4 h-4 flex items-center justify-center flex-shrink-0 text-sm">
   266→                  {child.icon}
   267→                </span>
   268→
   269→                {/* Label */}
   270→                <span className="flex-1 text-sm leading-5 font-medium truncate">
   271→                  {child.label}
   272→                </span>
   273→              </Link>
   274→            </li>
   275→          ))}
   276→        </ul>
   277→      )}
   278→    </li>
   279→  );
   280→};
   281→
   282→export const Sidebar: React.FC = () => {
   283→  const { isCollapsed, toggleCollapse, isMobileMenuOpen, setMobileMenuOpen } = useSidebarStore();
   284→  const { mode, toggleTheme } = useThemeStore();
   285→  const navOrder = useSidebarNavStore((state) => state.navOrder);
   286→  const setNavOrder = useSidebarNavStore((state) => state.setNavOrder);
   287→  const { isExpanded, toggleExpanded } = useNavExpansionStore();
   288→  const location = useLocation();
   289→  const [pageSettingsOpen, setPageSettingsOpen] = useState<string | null>(null);
   290→  const [justDragged, setJustDragged] = useState(false);
   291→  const navigate = useNavigate();
   292→  const getOrCreateDailyNote = useNotesStore((state) => state.getOrCreateDailyNote);
   293→  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
   294→
   295→  // Check if a nav path is active (handles both pathname and query params)
   296→  const isActive = (path: string) => {
   297→    // Handle paths with query params (e.g., /schedule?tab=calendar)
   298→    if (path.includes('?')) {
   299→      const [pathname, query] = path.split('?');
   300→      if (location.pathname !== pathname) return false;
   301→      const params = new URLSearchParams(query);
   302→      const currentParams = new URLSearchParams(location.search);
   303→      // Check if all specified params match
   304→      for (const [key, value] of params.entries()) {
   305→        if (currentParams.get(key) !== value) return false;
   306→      }
   307→      return true;
   308→    }
   309→    // Simple pathname match
   310→    return location.pathname === path;
   311→  };
   312→
   313→  // Check if any child of a parent is active (for highlighting parent when child is active)
   314→  const isChildActive = (item: NavItem) => {
   315→    if (!item.children) return false;
   316→    return item.children.some((child) => isActive(child.path));
   317→  };
   318→
   319→  // Configure drag sensors (require 5px movement to start dragging)
   320→  const sensors = useSensors(
   321→    useSensor(PointerSensor, {
   322→      activationConstraint: {
   323→        distance: 5,
   324→      },
   325→    })
   326→  );
   327→
   328→  // Sort draggable navigation items by saved order
   329→  const sortedDraggableNavigation = [...draggableNavigation].sort((a, b) => {
   330→    const aIndex = navOrder.indexOf(a.path);
   331→    const bIndex = navOrder.indexOf(b.path);
   332→    // If path not found in order, put it at the end
   333→    return (aIndex === -1 ? 999 : aIndex) - (bIndex === -1 ? 999 : bIndex);
   334→  });
   335→
   336→  const handleDragEnd = (event: DragEndEvent) => {
   337→    const { active, over } = event;
   338→
   339→    setJustDragged(true);
   340→
   341→    if (over && active.id !== over.id) {
   342→      const oldIndex = navOrder.indexOf(active.id as string);
   343→      const newIndex = navOrder.indexOf(over.id as string);
   344→
   345→      if (oldIndex !== -1 && newIndex !== -1) {
   346→        const newOrder = arrayMove(navOrder, oldIndex, newIndex);
   347→        setNavOrder(newOrder);
   348→      }
   349→    }
   350→
   351→    // Reset justDragged flag after a short delay
   352→    setTimeout(() => setJustDragged(false), 100);
   353→  };
   354→
   355→  const handlePageSettings = (e: React.MouseEvent, path: string) => {
   356→    e.preventDefault();
   357→    e.stopPropagation();
   358→    setPageSettingsOpen(path);
   359→  };
   360→
   361→  // Close mobile menu on route change
   362→  useEffect(() => {
   363→    setMobileMenuOpen(false);
   364→  }, [location.pathname, setMobileMenuOpen]);
   365→
   366→  // Keyboard shortcut: Cmd/Ctrl + B to toggle sidebar
   367→  useEffect(() => {
   368→    const handleKeyDown = (e: KeyboardEvent) => {
   369→      if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
   370→        e.preventDefault();
   371→        toggleCollapse();
   372→      }
   373→    };
   374→
   375→    window.addEventListener('keydown', handleKeyDown);
   376→    return () => window.removeEventListener('keydown', handleKeyDown);
   377→  }, [toggleCollapse]);
   378→
   379→  // Keyboard shortcut: Cmd/Ctrl + D to open today's daily note
   380→  useEffect(() => {
   381→    const handleKeyDown = (e: KeyboardEvent) => {
   382→      if ((e.metaKey || e.ctrlKey) && e.key === 'd' && dailyNotesEnabled) {
   383→        e.preventDefault();
   384→        handleTodayClick();
   385→      }
   386→    };
   387→
   388→    window.addEventListener('keydown', handleKeyDown);
   389→    return () => window.removeEventListener('keydown', handleKeyDown);
   390→  }, [dailyNotesEnabled]);
   391→
   392→  // Handler for "Today" button click
   393→  const handleTodayClick = () => {
   394→    const today = new Date();
   395→    getOrCreateDailyNote(today); // Auto-selects the note by setting activeNoteId
   396→    navigate('/notes');
   397→  };
   398→
   399→  return (
   400→    <>
   401→      {/* Mobile backdrop */}
   402→      {isMobileMenuOpen && (
   403→        <div
   404→          className="lg:hidden fixed inset-0 bg-black/50 z-30"
   405→          onClick={() => setMobileMenuOpen(false)}
   406→        />
   407→      )}
   408→
   409→      {/* Sidebar */}
   410→      <aside
   411→        aria-label="Main navigation sidebar"
   412→        className={`
   413→          fixed left-0 top-0 h-screen
   414→          bg-surface-light-elevated dark:bg-surface-dark
   415→          border-r border-border-light dark:border-border-dark
   416→          transition-all duration-200 ease-in-out
   417→          flex flex-col
   418→          z-40
   419→          ${isCollapsed ? 'w-[60px]' : 'w-[210px]'}
   420→
   421→          ${/* Mobile: slide in/out as drawer */ ''}
   422→          lg:translate-x-0
   423→          ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
   424→        `}
   425→      >
   426→      {/* Logo Section */}
   427→      <div className="p-4 border-b border-border-light dark:border-border-dark">
   428→        <Link
   429→          to="/"
   430→          className="flex items-center gap-3 overflow-hidden"
   431→        >
   432→          <img
   433→            src="/images/logos/nb3.png"
   434→            alt="Neuman Brain"
   435→            className="w-8 h-8 flex-shrink-0 rounded-button"
   436→          />
   437→          {!isCollapsed && (
   438→            <div className="flex flex-col min-w-0">
   439→              <h1 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary truncate">
   440→                NEUMAN BRAIN
   441→              </h1>
   442→              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary truncate">
   443→                Management Platform
   444→              </p>
   445→            </div>
   446→          )}
   447→        </Link>
   448→      </div>
   449→
   450→      {/* Navigation Items */}
   451→      <nav aria-label="Primary navigation" className="flex-1 overflow-y-auto py-4">
   452→        <ul className="space-y-1 px-2">
   453→          {/* Fixed Navigation Items (Dashboard - not draggable, supports children) */}
   454→          {fixedNavigation.map((item) => {
   455→            const hasChildren = item.children && item.children.length > 0;
   456→            const expanded = isExpanded(item.path);
   457→            const parentActive = isActive(item.path);
   458→            const childActive = isChildActive(item);
   459→
   460→            return (
   461→              <li key={item.path}>
   462→                {/* Parent Item */}
   463→                <div className="flex items-center">
   464→                  <Link
   465→                    to={item.path}
   466→                    className={`
   467→                      flex-1 flex items-center gap-3 px-3 h-10 rounded-button
   468→                      transition-all duration-standard ease-smooth
   469→                      relative group
   470→                      ${
   471→                        parentActive || childActive
   472→                          ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   473→                          : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   474→                      }
   475→                    `}
   476→                    title={isCollapsed ? item.label : undefined}
   477→                  >
   478→                    {/* Active indicator (left accent) */}
   479→                    {parentActive && (
   480→                      <div className="absolute left-0 top-2 bottom-2 w-[3px] bg-accent-blue rounded-r" />
   481→                    )}
   482→
   483→                    {/* Icon - Fixed 20px size */}
   484→                    <span className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg">
   485→                      {item.icon}
   486→                    </span>
   487→
   488→                    {/* Label (hidden when collapsed) */}
   489→                    {!isCollapsed && (
   490→                      <>
   491→                        <span className="flex-1 text-base leading-5 font-medium truncate">
   492→                          {item.label}
   493→                        </span>
   494→
   495→                        {/* Page Settings Icon (shown on hover) */}
   496→                        {item.hasSettings && (
   497→                          <button
   498→                            onClick={(e) => handlePageSettings(e, item.path)}
   499→                            className="
   500→                              opacity-0 group-hover:opacity-100
   501→                              w-5 h-5 flex items-center justify-center flex-shrink-0
   502→                              text-text-light-secondary dark:text-text-dark-secondary
   503→                              hover:text-text-light-primary dark:hover:text-text-dark-primary
   504→                              transition-opacity duration-200
   505→                            "
   506→                            title="Page Settings"
   507→                          >
   508→                            <span className="text-sm">⚙</span>
   509→                          </button>
   510→                        )}
   511→
   512→                        {/* Expand/Collapse Chevron (for items with children) */}
   513→                        {hasChildren && (
   514→                          <button
   515→                            onClick={(e) => {
   516→                              e.preventDefault();
   517→                              e.stopPropagation();
   518→                              toggleExpanded(item.path);
   519→                            }}
   520→                            className="
   521→                              w-5 h-5 flex items-center justify-center flex-shrink-0
   522→                              text-text-light-secondary dark:text-text-dark-secondary
   523→                              hover:text-text-light-primary dark:hover:text-text-dark-primary
   524→                              transition-transform duration-200
   525→                            "
   526→                            title={expanded ? 'Collapse' : 'Expand'}
   527→                          >
   528→                            <span
   529→                              className={`text-xs transition-transform duration-200 ${
   530→                                expanded ? 'rotate-90' : ''
   531→                              }`}
   532→                            >
   533→                              ▶
   534→                            </span>
   535→                          </button>
   536→                        )}
   537→                      </>
   538→                    )}
   539→
   540→                    {/* Tooltip for collapsed state */}
   541→                    {isCollapsed && (
   542→                      <div className="
   543→                        absolute left-full ml-2 px-2 py-1
   544→                        bg-surface-light-elevated dark:bg-surface-dark-elevated
   545→                        text-text-light-primary dark:text-text-dark-primary text-xs rounded
   546→                        opacity-0 group-hover:opacity-100
   547→                        pointer-events-none transition-opacity duration-200
   548→                        whitespace-nowrap z-50
   549→                      ">
   550→                        {item.label}
   551→                      </div>
   552→                    )}
   553→                  </Link>
   554→                </div>
   555→
   556→                {/* Children (Sub-pages) - only show when expanded and not collapsed */}
   557→                {hasChildren && expanded && !isCollapsed && (
   558→                  <ul className="ml-6 mt-1 space-y-1">
   559→                    {item.children!.map((child) => (
   560→                      <li key={child.path}>
   561→                        <Link
   562→                          to={child.path}
   563→                          className={`
   564→                            flex items-center gap-3 px-3 h-9 rounded-button
   565→                            transition-all duration-standard ease-smooth
   566→                            relative group
   567→                            ${
