        </button>
      </div>
    </aside>

    {/* Page Settings Panel */}
    {pageSettingsOpen && (
      <PageSettingsPanel
        isOpen={true}
        onClose={() => setPageSettingsOpen(null)}
        pagePath={pageSettingsOpen}
      />
    )}
    </>
  );
};

