   323→  );
   324→
   325→  // Sort draggable navigation items by saved order
   326→  const sortedDraggableNavigation = [...draggableNavigation].sort((a, b) => {
   327→    const aIndex = navOrder.indexOf(a.path);
   328→    const bIndex = navOrder.indexOf(b.path);
   329→    // If path not found in order, put it at the end
   330→    return (aIndex === -1 ? 999 : aIndex) - (bIndex === -1 ? 999 : bIndex);
   331→  });
   332→
   333→  const handleDragEnd = (event: DragEndEvent) => {
   334→    const { active, over } = event;
   335→
   336→    console.log('[Sidebar] Drag ended, setting justDragged flag');
   337→    justDraggedRef.current = true;
   338→
   339→    if (over && active.id !== over.id) {
   340→      const oldIndex = navOrder.indexOf(active.id as string);
   341→      const newIndex = navOrder.indexOf(over.id as string);
   342→
   343→      if (oldIndex !== -1 && newIndex !== -1) {
   344→        const newOrder = arrayMove(navOrder, oldIndex, newIndex);
   345→        setNavOrder(newOrder);
   346→      }
   347→    }
   348→
   349→    // Reset justDragged flag after a delay to prevent accidental navigation
   350→    setTimeout(() => {
   351→      console.log('[Sidebar] Clearing justDragged flag after 500ms');
   352→      justDraggedRef.current = false;
   353→    }, 500);
   354→  };
   355→
   356→  const handlePageSettings = (e: React.MouseEvent, path: string) => {
   357→    e.preventDefault();
   358→    e.stopPropagation();
   359→    setPageSettingsOpen(path);
   360→  };
   361→
   362→  // Close mobile menu on route change
   363→  useEffect(() => {
   364→    setMobileMenuOpen(false);
   365→  }, [location.pathname, setMobileMenuOpen]);
   366→
   367→  // Handler for "Today" button click
   368→  const handleTodayClick = () => {
   369→    const today = new Date();
   370→    getOrCreateDailyNote(today); // Auto-selects the note by setting activeNoteId
   371→    navigate('/notes');
   372→  };
   373→
   374→  // Keyboard shortcut: Cmd/Ctrl + B to toggle sidebar
   375→  useEffect(() => {
   376→    const handleKeyDown = (e: KeyboardEvent) => {
   377→      if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
   378→        e.preventDefault();
   379→        toggleCollapse();
   380→      }
   381→    };
   382→
   383→    window.addEventListener('keydown', handleKeyDown);
   384→    return () => window.removeEventListener('keydown', handleKeyDown);
   385→  }, [toggleCollapse]);
   386→
   387→  // Keyboard shortcut: Cmd/Ctrl + D to open today's daily note
   388→  useEffect(() => {
   389→    const handleKeyDown = (e: KeyboardEvent) => {
   390→      if ((e.metaKey || e.ctrlKey) && e.key === 'd' && dailyNotesEnabled) {
   391→        e.preventDefault();
   392→        handleTodayClick();
   393→      }
   394→    };
   395→
   396→    window.addEventListener('keydown', handleKeyDown);
   397→    return () => window.removeEventListener('keydown', handleKeyDown);
   398→  }, [dailyNotesEnabled, handleTodayClick]);
   399→
   400→  return (
   401→    <>
   402→      {/* Mobile backdrop */}
   403→      {isMobileMenuOpen && (
   404→        <div
   405→          className="lg:hidden fixed inset-0 bg-black/50 z-30"
   406→          onClick={() => setMobileMenuOpen(false)}
   407→        />
   408→      )}
   409→
   410→      {/* Sidebar */}
   411→      <aside
   412→        aria-label="Main navigation sidebar"
   413→        className={`
   414→          fixed left-0 top-0 h-screen
   415→          bg-surface-light-elevated dark:bg-surface-dark
   416→          border-r border-border-light dark:border-border-dark
   417→          transition-all duration-200 ease-in-out
   418→          flex flex-col
   419→          z-40
   420→          ${isCollapsed ? 'w-[60px]' : 'w-[210px]'}
   421→
   422→          ${/* Mobile: slide in/out as drawer */ ''}
   423→          lg:translate-x-0
   424→          ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
   425→        `}
   426→      >
   427→      {/* Logo Section */}
   428→      <div className="p-4 border-b border-border-light dark:border-border-dark">
   429→        <Link
   430→          to="/"
   431→          className="flex items-center gap-3 overflow-hidden"
   432→        >
   433→          <img
   434→            src="/images/logos/nb3.png"
   435→            alt="Neuman Brain"
   436→            className="w-8 h-8 flex-shrink-0 rounded-button"
   437→          />
   438→          {!isCollapsed && (
   439→            <div className="flex flex-col min-w-0">
   440→              <h1 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary truncate">
   441→                NEUMAN BRAIN
   442→              </h1>
   443→              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary truncate">
   444→                Management Platform
   445→              </p>
   446→            </div>
   447→          )}
   448→        </Link>
   449→      </div>
   450→
   451→      {/* Navigation Items */}
   452→      <nav aria-label="Primary navigation" className="flex-1 overflow-y-auto py-4">
   453→        <ul className="space-y-1 px-2">
   454→          {/* Fixed Navigation Items (Dashboard - not draggable, supports children) */}
   455→          {fixedNavigation.map((item) => {
   456→            const hasChildren = item.children && item.children.length > 0;
   457→            const expanded = isExpanded(item.path);
   458→            const parentActive = isActive(item.path);
   459→            const childActive = isChildActive(item);
   460→
   461→            return (
   462→              <li key={item.path}>
   463→                {/* Parent Item */}
   464→                <div className="flex items-center">
   465→                  <Link
