   467→                    className={`
   468→                      flex-1 flex items-center gap-3 px-3 h-10 rounded-button
   469→                      transition-all duration-standard ease-smooth
   470→                      relative group
   471→                      ${
   472→                        parentActive || childActive
   473→                          ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   474→                          : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   475→                      }
   476→                    `}
   477→                    title={isCollapsed ? item.label : undefined}
   478→                  >
   479→                    {/* Active indicator (left accent) */}
   480→                    {parentActive && (
