   523→                              text-text-light-secondary dark:text-text-dark-secondary
   524→                              hover:text-text-light-primary dark:hover:text-text-dark-primary
   525→                              transition-transform duration-200
   526→                            "
   527→                            title={expanded ? 'Collapse' : 'Expand'}
   528→                          >
   529→                            <span
   530→                              className={`text-xs transition-transform duration-200 ${
