   532→                              }`}
   533→                            >
   534→                              ▶
   535→                            </span>
   536→                          </button>
   537→                        )}
   538→                      </>
   539→                    )}
   540→
   541→                    {/* Tooltip for collapsed state */}
   542→                    {isCollapsed && (
   543→                      <div className="
   544→                        absolute left-full ml-2 px-2 py-1
   545→                        bg-surface-light-elevated dark:bg-surface-dark-elevated
   546→                        text-text-light-primary dark:text-text-dark-primary text-xs rounded
