   554→                  </Link>
   555→                </div>
   556→
   557→                {/* Children (Sub-pages) - only show when expanded and not collapsed */}
   558→                {hasChildren && expanded && !isCollapsed && (
   559→                  <ul className="ml-6 mt-1 space-y-1">
